  const departments = opts.role === "ADMIN" ? await pool`
          SELECT id, name FROM "Department" ORDER BY name ASC
        ` : opts.departmentId ? await pool`
            SELECT id, name FROM "Department" WHERE id = ${opts.departmentId}
          ` : [];
